WITH src(codigo_evento, descricao_evento, impacta_dre, impacta_caixa, exige_contrato, exige_centro_custo, observacao) AS (VALUES
('EVT-001','NF entrada de material para estoque',false,'NAO',true,false,'Bloquear sem 3-way match.'),
('EVT-002','NF entrada de material consumo direto contrato',true,'NAO',true,true,'Exige contrato e centro de custo.'),
('EVT-003','NF entrada de serviço administrativo',true,'NAO',false,true,'Exige centro de custo administrativo; aplicar rateio se serviço comum.'),
('EVT-004','Pagamento fornecedor',false,'SIM',false,false,'Não gera nova despesa; baixa obrigação.'),
('EVT-005','NF saída / faturamento contrato',true,'NAO',true,true,'Exige contrato, medição, empenho e regra fiscal.'),
('EVT-006','Tributos sobre faturamento',true,'NAO',true,true,'Reconhecer por competência.'),
('EVT-007','Recebimento cliente',false,'SIM',false,false,'Não gera nova receita; baixa cliente.'),
('EVT-008','Provisão mensal de folha operacional',true,'NAO',true,true,'Nasce por competência.'),
('EVT-009','Pagamento folha',false,'SIM',false,false,'Não duplica custo de pessoal.'),
('EVT-010','Recolhimento FGTS/INSS/tributos folha',false,'SIM',false,false,'Separar competência e caixa.'),
('EVT-011','Mútuo intercompany saída',false,'SIM',false,false,'Não entra na DRE; exige espelho e eliminação no consolidado.'),
('EVT-012','Mútuo intercompany entrada',false,'SIM',false,false,'Não entra na DRE; exige espelho e eliminação no consolidado.'),
('EVT-013','Rateio administrativo intercompany',true,'DEPENDE',true,true,'Critério de rateio obrigatório.'),
('EVT-014','Ajuste contábil manual',false,'DEPENDE',false,false,'Exige documento, justificativa e alçada.'),
('EVT-015','Baixa de estoque para contrato',true,'NAO',true,true,'Não gera caixa; movimenta orçamento realizado.')
)
UPDATE public.regra_contabilizacao rc
SET descricao = s.descricao_evento,
    entra_dre = s.impacta_dre,
    impacta_caixa = s.impacta_caixa,
    exige_contrato = s.exige_contrato,
    exige_centro_custo = s.exige_centro_custo,
    observacao = s.observacao,
    updated_at = now()
FROM src s
WHERE rc.codigo_evento = s.codigo_evento;

